mapper.select:
SELECT MEM_NAME , COUNSEL_NAME , COUNSEL_CATEGORY , COUNSEL_METHOD , COUNSEL_TITLE , COUNSEL_DESCRIPTION , COUNSEL_STATUS , COUNSEL_REQ_DATE , COUNSEL_REQ_TIME , COUNSEL_URL , COUNSEL_REVIEWD , COUNSEL_CREATED_AT , COUNSEL_UPDATED_AT FROM ( SELECT ROWNUM , D.* FROM ( SELECT A.COUNSEL_ID , M1.MEM_NAME AS MEM_NAME , M2.MEM_NAME AS COUNSEL_NAME , A.COUNSEL_CATEGORY , A.COUNSEL_METHOD , A.COUNSEL_TITLE , A.COUNSEL_DESCRIPTION , A.COUNSEL_STATUS , A.COUNSEL_REQ_DATE , A.COUNSEL_REQ_TIME , A.COUNSEL_URL , A.COUNSEL_REVIEWD , A.COUNSEL_CREATED_AT , A.COUNSEL_UPDATED_AT FROM COUNSELING A LEFT JOIN MEMBER M1 ON A.MEM_ID = M1.MEM_ID LEFT JOIN MEMBER M2 ON A.COUNSEL = M2.MEM_ID WHERE A.MEM_ID = #{memId}
AND A.COUNSEL_TITLE LIKE '%' || #{keyword} || '%'
AND A.COUNSEL_DESCRIPTION LIKE '%' || #{keyword} || '%'
AND M2.COUNSEL_NAME LIKE '%' || #{keyword} || '%'
AND ( A.COUNSEL_TITLE LIKE '%' || #{keyword} || '%' OR A.COUNSEL_DESCRIPTION LIKE '%' || #{keyword} || '%' OR A.COUNSEL_NAME LIKE '%' || #{keyword} || '%' )
AND A.COUNSEL_METHOD = #{counselMethod}
AND A.COUNSEL_CATEGORY = #{counselCategory}
ORDER BY A.COUNSEL_REQ_DATE DESC ) D WHERE ROWNUM <= #{endRow} ) WHERE ROWNUM >= #{startRow}

SELECT COUNT(*) FROM COUNSELING A LEFT JOIN MEMBER M1 ON A.MEM_ID = M1.MEM_ID LEFT JOIN MEMBER M2 ON A.COUNSEL = M2.MEM_ID WHERE A.MEM_ID = #{memId}
AND A.COUNSEL_TITLE LIKE '%' || #{keyword} || '%'
AND A.COUNSEL_DESCRIPTION LIKE '%' || #{keyword} || '%'
AND M2.COUNSEL_NAME LIKE '%' || #{keyword} || '%'
AND ( A.COUNSEL_TITLE LIKE '%' || #{keyword} || '%' OR A.COUNSEL_DESCRIPTION LIKE '%' || #{keyword} || '%' OR A.COUNSEL_NAME LIKE '%' || #{keyword} || '%' )
AND A.COUNSEL_METHOD = #{counselMethod}
AND A.COUNSEL_CATEGORY = #{counselCategory}
